const eventos = $input.all();

if (!eventos || eventos.length === 0) {
  return [];
}

const agora = new Date();
const resultados = [];

for (const evento of eventos) {
  const e = evento.json;
  const inicio = new Date(e.start?.dateTime || e.start?.date);
  const diffMin = Math.round((inicio - agora) / 60000);

  // So alertar entre 10 e 20 minutos antes
  if (diffMin >= 10 && diffMin <= 20) {
    const hora = inicio.toLocaleTimeString('pt-BR', {
      hour: '2-digit',
      minute: '2-digit',
      timeZone: 'America/Araguaina'
    });

    const titulo = e.summary || '(Sem titulo)';
    const local = e.location || '';
    const link = e.hangoutLink || e.htmlLink || '';

    // Participantes
    const attendees = (e.attendees || []).map(a => a.displayName || a.email).slice(0, 5);
    const participantes = attendees.length > 0 ? attendees.join(', ') : 'Somente voce';

    let mensagem = `\u23f0 *LEMBRETE em ${diffMin} min*\n\n`;
    mensagem += `\ud83d\udcc5 *${titulo}*\n`;
    mensagem += `\ud83d\udd52 ${hora}\n`;
    if (local) mensagem += `\ud83d\udccd ${local}\n`;
    mensagem += `\ud83d\udc65 ${participantes}\n`;
    if (link) mensagem += `\n\ud83d\udd17 [Entrar na reuniao](${link})`;

    resultados.push({ json: {
      mensagem: mensagem,
      evento_id: e.id,
      titulo: titulo,
      minutos_restantes: diffMin
    }});
  }
}

return resultados;
